import{_ as o,o as p,c as t,a5 as a}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0027：UPS 保护标志","description":"","frontmatter":{"title":"教程 0027：UPS 保护标志","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0027-ups-c-protection-flags.html","status":"learning","visibility":"public","summary":"Imported from 0027-ups-c-protection-flags.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0027-ups-c-protection-flags.md","filePath":"content/power/lessons/0027-ups-c-protection-flags.md","lastUpdated":null}'),l={name:"content/power/lessons/0027-ups-c-protection-flags.md"};function i(s,e,r,n,c,d){return p(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="教程-0027-ups-保护标志" tabindex="-1">教程 0027：UPS 保护标志 <a class="header-anchor" href="#教程-0027-ups-保护标志" aria-label="Permalink to &quot;教程 0027：UPS 保护标志&quot;">​</a></h1><p>中文主讲。一个概念：把不间断电源（uninterruptible power supply / UPS）的采样值和参数表变成保护标志，让状态机不直接吞一堆零散阈值。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学采样序列和教学阈值，不包含公司内部保护阈值、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>UPS 保护标志（UPS protection flags）是把采样值（sampled measurement）和参数表比较后得到的一组布尔结果，例如欠压、过压、旁路不同步和是否需要停机。</p><p>本节只讲一个概念：<code>采样值 + 参数表 -&gt; 保护标志</code>。</p><p>保护标志不是故障锁存。这里的故障锁存（fault latch）描述“故障是否已经被确认并保持到复位”，保护标志只描述“此刻是否越界”。本节先讲前者，下一节再讲去抖和锁存。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 控制软件不能只看控制环路输出。市电异常、直流母线过压、旁路不同步等条件会直接影响模式切换、脉宽调制（pulse-width modulation / PWM）使能和故障锁存。</p><p>如果保护判断分散在状态机、驱动和控制环里，阅读工程时很难知道“这个故障是谁判出来的”。集中保护标志能让你先读清楚保护来源，再看状态机如何消费这些标志。</p><p>采样值先由模数转换器（analog-to-digital converter / ADC）采到原始码，再经采样调理和标定换算成 V、ms 等工程单位。采样值先换算成工程单位，再进入保护判断，这样保护模块才不需要理解 ADC 通道号和比例系数。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>保护模块像值班员。采样模块把电压、同步时间等读数送过来；参数表提供边界；保护模块只回答“是否越界”。状态机和输出模块再决定是否切换模式或关闭执行器。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>mains_undervoltage = mains_rms_v dc_bus_ov_threshold_v bypass_not_synchronized = bypass_sync_ms</p><p>关键术语：</p><ul><li><p>欠压保护（undervoltage protection / UVP）</p></li><li><p>过压保护（overvoltage protection / OVP）</p></li><li><p>旁路不同步（bypass not synchronized）</p></li><li><p>控制中断服务程序（control interrupt service routine / control ISR）</p></li></ul><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行 Python 仿真：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\ups_protection_flags.py</p><p>如果你只想保存图片、不自动打开：</p><p>python simulations\\python\\ups_protection_flags.py --no-open</p><pre><code>产物
</code></pre><ul><li><p><code>simulations/results/ups_protection_flags.png</code></p></li><li><p>终端输出：市电欠压、直流母线过压、旁路不同步和停机请求是否出现。</p></li><li><p>图内包含参数框、阈值线和每条曲线的图例。</p></li><li><p>C 程序输出：<code>protection_flags: mains_uv=1 dc_bus_ov=1 bypass_not_sync=1 shutdown=1</code></p></li></ul><p>观察顺序：先看市电 RMS 是否低于欠压阈值，再看直流母线是否高于过压阈值，最后看旁路同步保持时间是否达到要求。保护标志应该跟随这些越界条件变化。图中参数框会列出采样频率、仿真时长、欠压阈值、过压阈值和旁路同步保持时间。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><ul><li><p><code>UpsMeasurements</code>：采样后换算到工程单位的测量值。</p></li><li><p><code>UpsProtectionFlags</code>：保护判断结果。</p></li><li><p><code>UpsProtection_Evaluate()</code>：把测量值和 <code>UpsParameters</code> 组合，输出保护标志。</p></li><li><p><code>main.c</code>：打印教学保护标志，形成可向导师提问的具体产物。</p></li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**保护就是状态机里多写几个 if。 **纠正：**保护判断最好有清楚输入、阈值和输出标志，状态机消费标志。</p></li><li><p>**误解：**保护标志只要会触发停机就够了。 **纠正：**有些保护触发停机，有些只禁止旁路或降额，需要分层表达。</p></li><li><p>**误解：**仿真图只要看最终有没有故障。 **纠正：**要看采样量何时跨过阈值，以及保护标志是否同步变化。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能运行 <code>python simulations\\python\\ups_protection_flags.py --no-open</code> 并打开 <code>simulations/results/ups_protection_flags.png</code>。</p></li><li><p>能解释市电 RMS、直流母线和旁路同步保持时间分别如何触发保护标志。</p></li><li><p>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>protection_flags</code> 输出。</p></li><li><p>能基于 <code>protection.c -&gt; UpsProtection_Evaluate()</code> 准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么保护模块应该接收工程单位的采样值，而不是直接接收 ADC 原始码？</p></li><li><p>为什么旁路不同步不一定等于系统必须停机？</p></li><li><p>如果市电电压在阈值附近抖动，当前教学代码会出现什么问题？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>protection.c -&gt; UpsProtection_Evaluate()</code> 把采样值和参数表集中生成保护标志。真实工程里保护判断通常在控制 ISR、保护任务，还是状态机任务里执行？</p></li><li><p>我用 <code>simulations/results/ups_protection_flags.png</code> 看到采样量跨过阈值后标志变为 1。真实工程里保护通常会不会加滤波、去抖或保持时间？</p></li><li><p>我不会记录公司内部保护阈值，只想确认组织方式：真实工程里哪些保护会直接停机，哪些只影响旁路或输出许可？</p></li></ul><p>**下一步：**可以继续做保护去抖和故障锁存，把瞬时保护标志变成稳定、可复位、可记录的故障状态。</p><p>关联：<a href="./0026-ups-c-parameter-table.html">上一节：UPS C 参数表</a>；源稿：<code>concepts/embedded/ups-c-protection-flags.md</code>；仿真：<code>simulations/python/ups_protection_flags.py</code>。</p><pre><code>上一节：教程 0026：UPS C 参数表
下一节：教程 0028：保护去抖与故障锁存
</code></pre>`,40)])])}const _=o(l,[["render",i]]);export{h as __pageData,_ as default};
